import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.ResourceAccessException;

import javax.validation.Valid;
import javax.validation.constraints.NotBlank;
import javax.validation.constraints.NotNull;
import java.net.URI;
import java.net.URISyntaxException;
import java.util.*;

@RestController
@RequestMapping("/webhook")
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @Autowired
    private UrlValidator urlValidator;

    @PostMapping("/process")
    public ResponseEntity<Map<String, Object>> processWebhook(
            @RequestBody @Valid WebhookRequest request) {
        Map<String, Object> response = new HashMap<>();
        
        try {
            if (!urlValidator.isValidUrl(request.getUrl())) {
                response.put("error", "Invalid URL provided");
                return ResponseEntity.badRequest().body(response);
            }

            String content = fetchContent(request.getUrl(), request.getHeaders());
            response.put("status", "success");
            response.put("content", content);
            response.put("url", request.getUrl());
            
        } catch (HttpClientErrorException e) {
            response.put("error", "HTTP error: " + e.getMessage());
            return ResponseEntity.status(e.getStatusCode()).body(response);
        } catch (ResourceAccessException e) {
            response.put("error", "Connection error: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.GATEWAY_TIMEOUT).body(response);
        } catch (Exception e) {
            response.put("error", "Unexpected error: " + e.getMessage());
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(response);
        }
        
        return ResponseEntity.ok(response);
    }

    private String fetchContent(String url, Map<String, String> headers) {
        HttpHeaders httpHeaders = new HttpHeaders();
        if (headers != null) {
            headers.forEach(httpHeaders::set);
        }
        
        HttpEntity<String> entity = new HttpEntity<>(httpHeaders);
        
        return restTemplate.exchange(url, HttpMethod.GET, entity, String.class).getBody();
    }

    static class WebhookRequest {
        @NotBlank
        private String url;
        
        private Map<String, String> headers;
        
        public String getUrl() {
            return url;
        }
        
        public void setUrl(String url) {
            this.url = url;
        }
        
        public Map<String, String> getHeaders() {
            return headers;
        }
        
        public void setHeaders(Map<String, String> headers) {
            this.headers = headers;
        }
    }
}

@Component
class UrlValidator {
    
    private static final Set<String> ALLOWED_SCHEMES = Set.of("http", "https");
    private static final Set<String> BLOCKED_HOSTS = Set.of(
        "127.0.0.1", "localhost", "0.0.0.0", "::1",
        "10.", "172.16.", "172.17.", "172.18.", "172.19.", "172.20.", "172.21.", "172.22.", "172.23.", "172.24.", "172.25.", "172.26.", "172.27.", "172.28.", "172.29.", "172.30.", "172.31.",
        "192.168."
    );
    
    public boolean isValidUrl(String urlString) {
        if (urlString == null || urlString.isEmpty()) {
            return false;
        }
        
        try {
            URI uri = new URI(urlString);
            String scheme = uri.getScheme();
            String host = uri.getHost();
            
            if (!ALLOWED_SCHEMES.contains(scheme)) {
                return false;
            }
            
            if (host == null) {
                return false;
            }
            
            for (String blockedHost : BLOCKED_HOSTS) {
                if (host.startsWith(blockedHost)) {
                    return false;
                }
            }
            
            return true;
        } catch (URISyntaxException e) {
            return false;
        }
    }
}